module RefModule(sel,clk,reset,a,b,out );parameter width=8;
  input        [1:0] sel ;
  input         reset,     clk;
  input        [width-1:0] a;
  input        [width-1:0] b;
  output reg   [width-1:0] out;

wire [7:0] MUX [0:3];

  wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign MUX = {_n01, _n02, _n03, _n04};
assign MUX[1] = a-b;
assign MUX[2] = a^b;
assign MUX[3] = a&b;

always@(posedge clk)
begin
if (reset)
  out<=7'b0;
  else
  out <= MUX[sel];
end
 endmodule
